package com.example;

import org.eclipse.jdt.core.JavaCore;

public class MyProjectVersions {
    public static final String COMPLIANCE_VERSION_FIELD = JavaCore.VERSION_1_9;

    public void checkVersion(String currentVersion) {
        if (currentVersion.equals(JavaCore.VERSION_1_9)) {
            System.out.println("Using Java 1.9 compatibility.");
        }
    }
}

